const entries = [];
const skipped = [];
for (const [term, abbr, category, definition, related] of TERMS) {
  const k = term.toLowerCase();
  if (seen.has(k)) { skipped.push(term); continue; }
  seen.add(k);
  entries.push({ term, abbr, category, definition, related });
}

const lines = entries.map((e) =>
  `  { term: ${JSON.stringify(e.term)}, abbr: ${e.abbr ? JSON.stringify(e.abbr) : 'null'}, category: ${JSON.stringify(e.category)}, definition: ${JSON.stringify(e.definition)}, related: ${JSON.stringify(e.related)} },`
);

const out = `/* Batch 4 — ${entries.length} curated unique terms */\nexport const EXTRA_GLOSSARY_BATCH4 = [\n${lines.join('\n')}\n];\n`;
writeFileSync(new URL('../src/data/extraGlossaryBatch4.js', import.meta.url), out);

const cats = {};
for (const e of entries) cats[e.category] = (cats[e.category] || 0) + 1;
console.log(`Written ${entries.length} terms. Skipped ${skipped.length}: ${skipped.join(', ')}`);
Object.keys(cats).sort().forEach((c) => console.log(`  ${c}: +${cats[c]}`));